        // THEN the clone's outputSettings charset remains default (UTF-8) and parser trackErrors remains 0
        assertAll(
            () -> assertEquals("UTF-8", copy.outputSettings().charset().name(),
                "Clone's charset should remain default UTF-8 after original is modified"),
